// 1. Sadə indeks imzasını
interface Dictionary {
  [key: string]: string;
}
const translations: Dictionary = {
  "hello": "salam",
  "world": "dünya"
};
console.log(translations["hello"]); // Çıxış: salam
translations["welcome"] = "xoş gəldiniz"; // OK
console.log(translations); // Çıxış: { hello: "salam", world: "dünya", welcome: "xoş gəldiniz" }

// 2. Number indeks imzasını
interface NumberMap {
  [index: number]: string;
}
const codes: NumberMap = ["sıfır", "bir", "iki"];
console.log(codes[0]); // Çıxış: sıfır
codes[3] = "üç"; // OK
console.log(codes); // Çıxış: ["sıfır", "bir", "iki", "üç"]

// 3. Readonly indeks imzasını
interface ReadonlyDictionary {
  readonly [key: string]: string;
}
const constants: ReadonlyDictionary = {
  "pi": "3.14",
  "e": "2.71"
};
console.log(constants["pi"]); // Çıxış: 3.14
// constants["pi"] = "3.14159"; // Xəta: readonly xüsusiyyət dəyişdirilə bilməz

// 4. Konkret xüsusiyyətlərlə birlikdə
interface User {
  name: string;
  [key: string]: string | number;
}
const user: User = {
  name: "Murad",
  age: 25,
  city: "Baku"
};
console.log(user); // Çıxış: { name: "Murad", age: 25, city: "Baku" }
user.email = "murad@example.com"; // OK
console.log(user); // Çıxış: { name: "Murad", age: 25, city: "Baku", email: "murad@example.com" }

// 5. Siniflərdə indeks imzasını
interface Config {
  [key: string]: string;
}
class Settings implements Config {
  [key: string]: string;
  constructor() {
    this["theme"] = "dark";
    this["language"] = "en";
  }
  getSetting(key: string): string {
    return this[key];
  }
}
const settings = new Settings();
console.log(settings.getSetting("theme")); // Çıxış: dark
settings["font"] = "Arial"; // OK
console.log(settings); // Çıxış: Settings { theme: "dark", language: "en", font: "Arial" }

// 6. Union tipləri ilə indeks imzasını
type Data = { type: "book"; title: string } | { type: "movie"; duration: number };
interface DataMap {
  [key: string]: Data;
}
const media: DataMap = {
  item1: { type: "book", title: "TypeScript Guide" },
  item2: { type: "movie", duration: 148 }
};
console.log(media["item1"]); // Çıxış: { type: "book", title: "TypeScript Guide" }
console.log(media["item2"]); // Çıxış: { type: "movie", duration: 148 }

// Sadə mağaza sistemi
interface ProductAttributes {
  readonly [key: string]: string;
}
interface Product {
  id: string;
  name: string;
  attributes: ProductAttributes;
}
class ProductItem implements Product {
  id: string;
  name: string;
  attributes: ProductAttributes;
  constructor(id: string, name: string, attributes: ProductAttributes) {
    this.id = id;
    this.name = name;
    this.attributes = attributes;
  }
  getDetails(): string {
    let details = `${this.name} (ID: ${this.id})`;
    for (const key in this.attributes) {
      details += `, ${key}: ${this.attributes[key]}`;
    }
    return details;
  }
}
const laptop = new ProductItem("P001", "Laptop", { color: "black", size: "15 inch" });
console.log(laptop.getDetails()); // Çıxış: Laptop (ID: P001), color: black, size: 15 inch
// laptop.attributes.color = "silver"; // Xəta: readonly xüsusiyyət dəyişdirilə bilməz

// İndeks imzasını type aliases ilə
 type ConfigMap = { [key: string]: string };
const config: ConfigMap = {
  apiKey: "abc123",
  endpoint: "https://api.example.com"
};
console.log(config); // Çıxış: { apiKey: "abc123", endpoint: "https://api.example.com" }
config["timeout"] = "5000"; // OK
console.log(config); // Çıxış: { apiKey: "abc123", endpoint: "https://api.example.com", timeout: "5000" }

